changeSet.sql:
CREATE TABLE IF NOT EXISTS specialist_profile (
    id              VARCHAR(36) PRIMARY KEY,
    user_id         VARCHAR(36) NOT NULL UNIQUE,
    description     TEXT,
    active          BOOLEAN NOT NULL,
    rating          DOUBLE PRECISION NOT NULL DEFAULT 0,
    reviews_count   INTEGER NOT NULL DEFAULT 0
    );

CREATE INDEX IF NOT EXISTS idx_specialist_profile_active
    ON specialist_profile (active);

CREATE INDEX IF NOT EXISTS idx_specialist_profile_user
    ON specialist_profile (user_id);
